class Solution(object):
    def specialPerm(self, nums):
        MOD = 10**9 + 7
        n = len(nums)
        full_mask = (1 << n) - 1
        # dp[mask][i] = number of special permutations using elements in mask, ending at index i
        dp = [[0] * n for _ in range(1 << n)]
        for i in range(n):
            dp[1 << i][i] = 1

        for mask in range(1, 1 << n):
            for last in range(n):
                if not dp[mask][last]:
                    continue
                if not (mask >> last & 1):
                    continue
                for nxt in range(n):
                    if mask >> nxt & 1:
                        continue
                    a, b = nums[last], nums[nxt]
                    if a % b == 0 or b % a == 0:
                        dp[mask | (1 << nxt)][nxt] = (dp[mask | (1 << nxt)][nxt] + dp[mask][last]) % MOD

        return sum(dp[full_mask]) % MOD
